import React from 'react';
import { DiscoveryStarRating } from '../discovery/DiscoveryStarRating.js';

export interface UseCase {
    name: string;
    score: number;
}

export interface UseCaseRatingsProps {
    useCases?: UseCase[];
    maxItems?: number;
}

/**
 * UseCaseRatings component displays use case relevance scores as star ratings.
 * Scores are 0-10, converted to 0-5 for display.
 */
export function UseCaseRatings({ useCases = [], maxItems = 4 }: UseCaseRatingsProps): JSX.Element | null {
    if (!useCases || useCases.length === 0) {
        return null;
    }

    // Sort alphabetically by name so use cases align across product cards
    const sortedUseCases = [...useCases].sort((a, b) => a.name.localeCompare(b.name));
    const displayedUseCases = sortedUseCases.slice(0, maxItems);

    // Convert score from 0-10 to 0-5 for star rating
    const scoreToStars = (score: number) => (score / 10) * 5;

    return (
        <div className="omniguide-cr-use-cases__container">
            {displayedUseCases.map((useCase, index) => (
                <div key={index} className="omniguide-cr-use-cases__row">
                    <span className="omniguide-cr-use-cases__label">{useCase.name}</span>
                    <DiscoveryStarRating rating={scoreToStars(useCase.score)} />
                </div>
            ))}
        </div>
    );
}
