/**
 * BCCategoryRecommendations — Category recommendations questionnaire for BigCommerce.
 *
 * Supports two variants:
 * - "conversational": one question at a time via WebSocket, like product flow
 * - "traditional": all questions loaded upfront, multi-step form, then submit
 *
 * Selected by `config.features.conversationalCategoryGuide` flag.
 */

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import DOMPurify from 'dompurify';
import {
  DiscoveryQuestionnaire as DefaultDiscoveryQuestionnaire,
  CategoryResultsPanel as DefaultCategoryResultsPanel,
  CategoryQuestionSkeleton,
  QuestionnaireTeaser,
  useOmniguideContext,
  useComponent,
  type FeedbackData,
  type AnsweredQuestionEntry,
  type DiscoveryQuestion,
} from '@swiftotter/omniguide-react';
import { FLOW_STATES } from '@swiftotter/omniguide-core';
import { useBCCategoryQuestions } from '../hooks/useBCCategoryQuestions.js';
import { useBCCategoryWebSocket } from '../hooks/useBCCategoryWebSocket.js';
import { formatSeoSummary } from '../formatSeoSummary.js';

// ── Types ──────────────────────────────────────────────────────────

export interface BCCategoryRecommendationsProps {
  onShowResults?: (showing: boolean, loading?: boolean) => void;
  onSuggestedQuestionsLoad?: (questions: string[]) => void;
}

// ── Constants ──────────────────────────────────────────────────────

const MOBILE_BREAKPOINT = 768;

const isMobileViewport = () =>
  typeof window !== 'undefined' && window.innerWidth <= MOBILE_BREAKPOINT;

// ── Helper: scroll to element ──────────────────────────────────────

function scrollToElement(element: HTMLElement | null): void {
  if (!element) return;
  setTimeout(() => {
    if (!element) return;
    const header = document.querySelector('header');
    const headerHeight = header ? (header as HTMLElement).offsetHeight : 0;
    const rect = element.getBoundingClientRect();
    const scrollTop = window.pageYOffset || document.documentElement.scrollTop;
    const elementTop = rect.top + scrollTop;
    const targetScroll = elementTop - headerHeight;

    if (rect.top < headerHeight) {
      window.scrollTo({ top: Math.max(0, targetScroll), behavior: 'smooth' });
    }
  }, 100);
}

// ── Storage helpers for results collapsed state ────────────────────

function loadResultsCollapsed(storageKey: string): boolean {
  try {
    return sessionStorage.getItem(storageKey) === 'true';
  } catch {
    return false;
  }
}

function saveResultsCollapsed(storageKey: string, collapsed: boolean): void {
  try {
    sessionStorage.setItem(storageKey, collapsed ? 'true' : 'false');
  } catch {
    // Ignore storage errors
  }
}

const QuestionsErrorState: React.FC<{ onRetry?: () => void }> = ({ onRetry }) => (
  <div className="omniguide-cr-state omniguide-cr-state--error">
    <h3 className="omniguide-cr-state__title">Unable to connect</h3>
    <p className="omniguide-cr-state__text">
      The service is currently unavailable. Please try again in a moment.
    </p>
    <button
      type="button"
      className="omniguide-cr-state__retry-btn"
      onClick={onRetry}
    >
      <span>Try Again</span>
    </button>
  </div>
);

// ── Component ──────────────────────────────────────────────────────

export function BCCategoryRecommendations({
  onShowResults,
  onSuggestedQuestionsLoad,
}: BCCategoryRecommendationsProps): JSX.Element {
  const DiscoveryQuestionnaire = useComponent('DiscoveryQuestionnaire', DefaultDiscoveryQuestionnaire);
  const CategoryResultsPanel = useComponent('CategoryResultsPanel', DefaultCategoryResultsPanel);

  const { config, feedbackApi } = useOmniguideContext();
  const isConversational = config.features?.conversationalCategoryGuide ?? false;
  const teaserEnabled = config.features?.questionnaireTeaser?.categoryGuide ?? false;
  const resultsCollapsedKey = config.storageKeys?.resultsCollapsed ?? 'omniguideResultsCollapsed';
  const fallbackImage = config.fallbackImages?.product ?? '';
  const showProductTags = config.features?.productTags !== false;

  const containerRef = useRef<HTMLDivElement>(null);
  const shouldScrollToTopRef = useRef(false);

  // Config-level category URL override (for non-BC sites / mock store)
  const configCategoryUrl = config.categoryUrl;

  // Fetch questions from REST API
  const { questions: initialQuestions, categoryData, loading: questionsLoading, hasQuestions, error: questionsError, retry: retryQuestions } =
    useBCCategoryQuestions(configCategoryUrl);

  // WebSocket hook
  const {
    flowState,
    currentQuestion: wsQuestion,
    questionNumber,
    answeredQuestions,
    recommendations,
    isLoading: recommendationsLoading,
    error: recommendationsError,
    processingStatus,
    fallbackInfo,
    getStatusMessage,
    startConversation,
    resumeSession,
    submitAnswer,
    submitOtherAnswer,
    clearOtherError,
    resetConversation,
    getRecommendations,
    disconnect,
    otherValidationError,
    clarificationPrompt,
    isOtherProcessing,
    hasStoredSession,
  } = useBCCategoryWebSocket({ productTypeId: categoryData?.productTypeId as number | string | null });

  // Local state
  const [noQuestions, setNoQuestions] = useState(false);
  const [resultsCollapsed, setResultsCollapsed] = useState(() => loadResultsCollapsed(resultsCollapsedKey));
  const [resultsTruncated, setResultsTruncated] = useState(false);
  const [teaserExpanded, setTeaserExpanded] = useState(false);

  // ── Traditional-only state ────────────────────────────────────────
  const [currentStep, setCurrentStep] = useState(0);
  const [allAnsweredIntents, setAllAnsweredIntents] = useState<Record<string, { answer_id: string | number; answer: string }>>({});
  const [showResultsTrad, setShowResultsTrad] = useState(false);
  const skipAutoSubmitRef = useRef(false);
  const isAutoSubmitRef = useRef(false);

  // ── Conversational logic ──────────────────────────────────────────

  const firstQuestion = initialQuestions.length > 0 ? initialQuestions[0] : null;

  const currentQuestionConv = useMemo(() => {
    if (
      flowState === FLOW_STATES.IDLE ||
      flowState === FLOW_STATES.LOADING_FIRST ||
      flowState === FLOW_STATES.SHOWING_FIRST
    ) {
      return firstQuestion;
    }
    return wsQuestion;
  }, [flowState, firstQuestion, wsQuestion]);

  const showQuestionnaireConv = useMemo(() => {
    if (!hasQuestions) return false;
    const idleOrFirst = flowState === FLOW_STATES.IDLE || flowState === FLOW_STATES.SHOWING_FIRST;
    const questioning = flowState === FLOW_STATES.QUESTIONING && wsQuestion;
    return (idleOrFirst && firstQuestion) || questioning;
  }, [hasQuestions, flowState, firstQuestion, wsQuestion]);

  const showResultsConv = useMemo(() => {
    return (
      flowState === FLOW_STATES.LOADING_RESULTS ||
      flowState === FLOW_STATES.COMPLETE ||
      flowState === FLOW_STATES.ERROR
    );
  }, [flowState]);

  const questionsForIndicatorConv = useMemo(
    () => answeredQuestions.map((aq) => aq.question),
    [answeredQuestions],
  );

  const answeredIntentsForIndicatorConv = useMemo(() => {
    const intents: Record<string, { answer: string; [key: string]: unknown }> = {};
    answeredQuestions.forEach((aq) => {
      const qId = (aq.question as Record<string, unknown>)?.['id'];
      if (qId) {
        intents[String(qId)] = aq.answer as { answer: string };
      }
    });
    return intents;
  }, [answeredQuestions]);

  // ── Traditional: filter answered intents to current questions ──────

  const answeredIntentsTrad = useMemo(() => {
    if (initialQuestions.length === 0) return allAnsweredIntents;
    const questionIds = initialQuestions.map((q) => String(q['id']));
    return Object.fromEntries(
      Object.entries(allAnsweredIntents).filter(([id]) => questionIds.includes(id)),
    );
  }, [allAnsweredIntents, initialQuestions]);

  // ── Shared: which "show" flags to use ─────────────────────────────

  const effectiveShowResults = isConversational ? showResultsConv : showResultsTrad;
  const effectiveShowQuestionnaire = isConversational
    ? showQuestionnaireConv
    : (!questionsLoading && hasQuestions && !showResultsTrad);

  // ── Effects ───────────────────────────────────────────────────────

  // No questions
  useEffect(() => {
    if (!questionsLoading && !hasQuestions) {
      setNoQuestions(true);
    }
  }, [questionsLoading, hasQuestions]);

  // Resume session (conversational only)
  useEffect(() => {
    if (!isConversational) return;
    if (!questionsLoading && flowState === FLOW_STATES.IDLE && hasStoredSession()) {
      // Auto-expand teaser when resuming a stored session
      if (teaserEnabled && !teaserExpanded) setTeaserExpanded(true);
      const catUrl = categoryData?.categoryUrl || configCategoryUrl || window.location.pathname;
      resumeSession(catUrl);
    }
  }, [isConversational, questionsLoading, flowState, hasStoredSession, resumeSession, categoryData]);

  // Suggested questions
  useEffect(() => {
    if (categoryData?.suggestedQuestions?.length && onSuggestedQuestionsLoad) {
      onSuggestedQuestionsLoad(categoryData.suggestedQuestions);
    }
  }, [categoryData, onSuggestedQuestionsLoad]);

  // Notify parent of results (conversational)
  useEffect(() => {
    if (!isConversational) return;
    if (showResultsConv && !recommendationsLoading && flowState === FLOW_STATES.COMPLETE) {
      onShowResults?.(true);
    } else if (!showResultsConv) {
      onShowResults?.(false);
    }
  }, [isConversational, showResultsConv, recommendationsLoading, flowState, onShowResults]);

  // Notify parent of results (traditional)
  useEffect(() => {
    if (isConversational) return;
    if (showResultsTrad && !recommendationsLoading) {
      onShowResults?.(true);
    } else if (!showResultsTrad) {
      onShowResults?.(false);
    }
  }, [isConversational, showResultsTrad, recommendationsLoading, onShowResults]);

  // Traditional: auto-submit if all questions answered from storage
  useEffect(() => {
    if (isConversational) return;
    if (skipAutoSubmitRef.current) return;
    if (!questionsLoading && hasQuestions && !showResultsTrad && initialQuestions.length > 0 && currentStep === 0) {
      const allAnswered = initialQuestions.every((q) => answeredIntentsTrad[String(q['id'])]);
      if (allAnswered) {
        isAutoSubmitRef.current = true;
        const catUrl = categoryData?.categoryUrl || configCategoryUrl || window.location.pathname;
        getRecommendations(catUrl, answeredIntentsTrad as Record<string, unknown>, { maxResults: 2, generateCards: true });
        setShowResultsTrad(true);
        setResultsCollapsed(true);
        saveResultsCollapsed(resultsCollapsedKey, true);
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isConversational, questionsLoading, hasQuestions, initialQuestions.length, showResultsTrad, categoryData, getRecommendations, currentStep]);

  // Scroll on question/step change
  useEffect(() => {
    if (effectiveShowQuestionnaire) {
      scrollToElement(containerRef.current);
    }
  }, [effectiveShowQuestionnaire, isConversational ? questionNumber : currentStep]);

  // Scroll after returning from results
  useEffect(() => {
    if (shouldScrollToTopRef.current && !effectiveShowResults) {
      shouldScrollToTopRef.current = false;
      scrollToElement(containerRef.current);
    }
  }, [effectiveShowResults]);

  // Cleanup
  useEffect(() => {
    return () => {
      disconnect();
    };
  }, [disconnect]);

  // ── Conversational handlers ────────────────────────────────────────

  const handleSelectAnswerConv = useCallback(
    (questionId: string, answer: { id?: string | number; text: string }) => {
      if (!currentQuestionConv) return;

      const answerData = {
        questionId: String(questionId),
        answerId: answer.id != null ? String(answer.id) : null,
        answerText: answer.text,
      };

      const q = currentQuestionConv as Record<string, unknown>;
      if (flowState === FLOW_STATES.IDLE || flowState === FLOW_STATES.SHOWING_FIRST) {
        const catUrl = categoryData?.categoryUrl || configCategoryUrl || window.location.pathname;
        startConversation(catUrl, answerData, q);
      } else if (flowState === FLOW_STATES.QUESTIONING) {
        submitAnswer(answerData.questionId, answerData.answerId, answerData.answerText, q);
      }
    },
    [flowState, currentQuestionConv, categoryData, startConversation, submitAnswer],
  );

  const handleOtherSubmitConv = useCallback(
    (otherText: string) => {
      if (!currentQuestionConv) return;
      const q = currentQuestionConv as Record<string, unknown>;
      const qId = String(q['id']);

      if (flowState === FLOW_STATES.IDLE || flowState === FLOW_STATES.SHOWING_FIRST) {
        const catUrl = categoryData?.categoryUrl || configCategoryUrl || window.location.pathname;
        const answerData = { questionId: qId, answerId: null as string | null, answerText: otherText };
        startConversation(catUrl, answerData, q);
      } else if (flowState === FLOW_STATES.QUESTIONING) {
        submitOtherAnswer(qId, otherText, q);
      }
    },
    [currentQuestionConv, flowState, categoryData, startConversation, submitOtherAnswer],
  );

  // ── Traditional handlers ───────────────────────────────────────────

  const handleSelectAnswerTrad = useCallback(
    (questionId: string, answer: { id?: string | number; text: string }) => {
      setAllAnsweredIntents((prev) => ({
        ...prev,
        [questionId]: { answer_id: answer.id ?? '', answer: answer.text },
      }));
    },
    [],
  );

  const handleNext = useCallback(() => {
    if (currentStep < initialQuestions.length - 1) {
      setCurrentStep((prev) => prev + 1);
    }
  }, [currentStep, initialQuestions.length]);

  const handlePrevious = useCallback(() => {
    if (currentStep > 0) {
      setCurrentStep((prev) => prev - 1);
    }
  }, [currentStep]);

  const handleStepClick = useCallback(
    (stepIndex: number) => {
      if (stepIndex >= 0 && stepIndex < initialQuestions.length) {
        setCurrentStep(stepIndex);
      }
    },
    [initialQuestions.length],
  );

  const handleSubmitTrad = useCallback(() => {
    if (showResultsTrad || recommendationsLoading) return;
    skipAutoSubmitRef.current = false;
    isAutoSubmitRef.current = false;
    const catUrl = categoryData?.categoryUrl || configCategoryUrl || window.location.pathname;
    getRecommendations(catUrl, answeredIntentsTrad as Record<string, unknown>, { maxResults: 2, generateCards: true });
    setShowResultsTrad(true);

    if (isMobileViewport()) {
      setResultsTruncated(true);
      setResultsCollapsed(false);
      saveResultsCollapsed(resultsCollapsedKey, false);
    } else {
      setResultsCollapsed(false);
      saveResultsCollapsed(resultsCollapsedKey, false);
    }
  }, [categoryData, answeredIntentsTrad, getRecommendations, showResultsTrad, recommendationsLoading, resultsCollapsedKey]);

  // ── Shared handlers ────────────────────────────────────────────────

  const handleBack = useCallback(() => {
    shouldScrollToTopRef.current = true;

    if (isConversational) {
      resetConversation();
    } else {
      setShowResultsTrad(false);
      setCurrentStep(0);
      // Clear answers for current questions
      const questionIds = initialQuestions.map((q) => String(q['id']));
      setAllAnsweredIntents((prev) => {
        const updated = { ...prev };
        questionIds.forEach((id) => delete updated[id]);
        return updated;
      });
    }

    setResultsCollapsed(false);
    saveResultsCollapsed(resultsCollapsedKey, false);
    setResultsTruncated(false);
  }, [isConversational, resetConversation, initialQuestions, resultsCollapsedKey]);

  const handleResultsStepClick = useCallback(
    (stepIndex: number) => {
      if (isConversational) {
        handleBack();
      } else {
        if (stepIndex >= 0 && stepIndex < initialQuestions.length) {
          skipAutoSubmitRef.current = true;
          setShowResultsTrad(false);
          setCurrentStep(stepIndex);
        }
      }
    },
    [isConversational, handleBack, initialQuestions.length],
  );

  const handleCollapseToggle = useCallback(() => {
    setResultsCollapsed((prev) => {
      const newValue = !prev;
      saveResultsCollapsed(resultsCollapsedKey, newValue);
      return newValue;
    });
  }, [resultsCollapsedKey]);

  const handleTruncatedToggle = useCallback(() => {
    setResultsTruncated((prev) => !prev);
  }, []);

  // Feedback submit
  const handleFeedbackSubmit = useCallback(
    async (data: FeedbackData) => {
      if (!feedbackApi) throw new Error('Feedback API not available');
      return feedbackApi.submitFeedback({
        entityId: data.entity_id,
        entityType: data.entity_type as 'message' | 'product_recommendation' | 'category_recommendation',
        vote: data.vote as 1 | -1,
        comment: data.comment ?? '',
        context: data.context ?? {},
      });
    },
    [feedbackApi],
  );

  // Container class
  const getContainerClassName = () => {
    if (questionsLoading) {
      return 'omniguide-cr-container omniguide-cr-container--loading';
    }
    if (noQuestions && !categoryData?.shortSeoSummary && !questionsError) {
      return 'omniguide-cr-container omniguide-cr-container--collapsed';
    }
    return 'omniguide-cr-container';
  };

  // ── Render ────────────────────────────────────────────────────────

  if (isConversational) {
    // Conversational variant
    const questionsForQuestionnaire = currentQuestionConv ? [currentQuestionConv] : [];

    const questionnaireContent = (
      <>
        {questionsLoading && <CategoryQuestionSkeleton />}

        {/* Error state when questions fail to load */}
        {!questionsLoading && questionsError && !hasQuestions && (
          <QuestionsErrorState onRetry={retryQuestions} />
        )}

        {!questionsLoading && noQuestions && !questionsError && categoryData?.shortSeoSummary && (
          <div
            className="omniguide-cr-seo-summary"
            dangerouslySetInnerHTML={{ __html: DOMPurify.sanitize(formatSeoSummary(categoryData.shortSeoSummary)) }}
          />
        )}

        {!questionsLoading && showQuestionnaireConv && currentQuestionConv && (
          <DiscoveryQuestionnaire
            questions={questionsForQuestionnaire as DiscoveryQuestion[]}
            currentStep={0}
            answeredIntents={{}}
            onSelectAnswer={handleSelectAnswerConv}
            onNext={() => {}}
            onPrevious={() => {}}
            onSubmit={() => {}}
            onStepClick={() => {}}
            dynamicMode={true}
            answeredQuestions={answeredQuestions as AnsweredQuestionEntry[]}
            questionNumber={answeredQuestions.length + 1}
            onOtherSubmit={handleOtherSubmitConv}
            isOtherProcessing={isOtherProcessing}
            otherError={otherValidationError as { message: string } | null}
            clarificationPrompt={clarificationPrompt}
            onClearOtherError={clearOtherError}
          />
        )}

        {!questionsLoading &&
          !showQuestionnaireConv &&
          !showResultsConv &&
          (flowState === FLOW_STATES.CONNECTING ||
            (flowState === FLOW_STATES.QUESTIONING && !wsQuestion)) && (
            <div className="omniguide-cr-questionnaire">
              <CategoryQuestionSkeleton />
            </div>
          )}
      </>
    );

    // Show teaser when enabled and questionnaire is in its initial idle state
    const showTeaser = teaserEnabled && !teaserExpanded && flowState === FLOW_STATES.IDLE && !showResultsConv;

    return (
      <div ref={containerRef} className={getContainerClassName()}>
        {showTeaser ? (
          <QuestionnaireTeaser
            classPrefix="omniguide-cr"
            onExpand={() => setTeaserExpanded(true)}
          >
            {questionnaireContent}
          </QuestionnaireTeaser>
        ) : (
          questionnaireContent
        )}

        {showResultsConv && (
          <CategoryResultsPanel
            recommendations={recommendations as Record<string, unknown>[]}
            isLoading={recommendationsLoading || flowState === FLOW_STATES.LOADING_RESULTS}
            error={recommendationsError as { message?: string } | undefined}
            processingStatus={processingStatus ?? undefined}
            statusMessage={getStatusMessage() ?? undefined}
            fallbackInfo={fallbackInfo ? {
              used: fallbackInfo.used,
              reason: fallbackInfo.reason ?? undefined,
              scope: fallbackInfo.scope ?? undefined,
              explanation: fallbackInfo.explanation ?? undefined,
            } : undefined}
            onBack={handleBack}
            questions={questionsForIndicatorConv as Array<{ id?: string; question?: string; summary?: string }>}
            answeredIntents={answeredIntentsForIndicatorConv}
            onStepClick={handleResultsStepClick}
            onCollapse={handleCollapseToggle}
            isCollapsed={resultsCollapsed}
            isTruncated={resultsTruncated}
            onTruncatedToggle={handleTruncatedToggle}
            fallbackImage={fallbackImage}
            onFeedbackSubmit={handleFeedbackSubmit}
            showProductTags={showProductTags}
          />
        )}
      </div>
    );
  }

  // Traditional variant
  const tradQuestionnaireContent = (
    <>
      {questionsLoading && <CategoryQuestionSkeleton />}

      {/* Error state when questions fail to load */}
      {!questionsLoading && questionsError && !hasQuestions && (
        <div className="omniguide-cr-state omniguide-cr-state--error">
          <h3 className="omniguide-cr-state__title">Unable to connect</h3>
          <p className="omniguide-cr-state__text">
            The service is currently unavailable. Please try again in a moment.
          </p>
          <button
            type="button"
            className="omniguide-cr-state__retry-btn"
            onClick={retryQuestions}
          >
            <span>Try Again</span>
          </button>
        </div>
      )}

      {!questionsLoading && noQuestions && !questionsError && categoryData?.shortSeoSummary && (
        <div
          className="omniguide-cr-seo-summary"
          dangerouslySetInnerHTML={{ __html: DOMPurify.sanitize(formatSeoSummary(categoryData.shortSeoSummary)) }}
        />
      )}

      {effectiveShowQuestionnaire && (
        <DiscoveryQuestionnaire
          questions={initialQuestions as DiscoveryQuestion[]}
          currentStep={currentStep}
          answeredIntents={answeredIntentsTrad as Record<string, { answer: string }>}
          onSelectAnswer={handleSelectAnswerTrad}
          onNext={handleNext}
          onPrevious={handlePrevious}
          onSubmit={handleSubmitTrad}
          onStepClick={handleStepClick}
        />
      )}
    </>
  );

  // Show teaser when enabled, not expanded, and not showing results (including auto-submitted results)
  const showTeaserTrad = teaserEnabled && !teaserExpanded && !showResultsTrad;

  return (
    <div ref={containerRef} className={getContainerClassName()}>
      {showTeaserTrad ? (
        <QuestionnaireTeaser
          classPrefix="omniguide-cr"
          onExpand={() => setTeaserExpanded(true)}
        >
          {tradQuestionnaireContent}
        </QuestionnaireTeaser>
      ) : (
        tradQuestionnaireContent
      )}

      {showResultsTrad && (
        <CategoryResultsPanel
          recommendations={recommendations as Record<string, unknown>[]}
          isLoading={recommendationsLoading}
          error={recommendationsError as { message?: string } | undefined}
          processingStatus={processingStatus ?? undefined}
          statusMessage={getStatusMessage() ?? undefined}
          fallbackInfo={fallbackInfo ? {
            used: fallbackInfo.used,
            reason: fallbackInfo.reason ?? undefined,
            scope: fallbackInfo.scope ?? undefined,
            explanation: fallbackInfo.explanation ?? undefined,
          } : undefined}
          onBack={handleBack}
          questions={initialQuestions as Array<{ id?: string; question?: string; summary?: string }>}
          answeredIntents={answeredIntentsTrad as Record<string, { answer: string }>}
          onStepClick={handleResultsStepClick}
          onCollapse={handleCollapseToggle}
          isCollapsed={resultsCollapsed}
          isTruncated={resultsTruncated}
          onTruncatedToggle={handleTruncatedToggle}
          fallbackImage={fallbackImage}
          onFeedbackSubmit={handleFeedbackSubmit}
          showProductTags={showProductTags}
        />
      )}
    </div>
  );
}
